-- 730001010 T11 Mob HP Bump.sql
-- Raises max health on every Tou Tou v11 spawned creature to make them hard to kill.
-- Members: 11,000,000 -> 50,000,000. Bosses: 22,000,000 -> 120,000,000.
-- Pairs with the v11_mob_dmg_taken_* damage-taken mitigation (code): minions take 25% dmg,
-- bosses 15% -> effective HP ~200M members / ~800M bosses vs a /testchar T10 player.
-- Idempotent: re-run safe (absolute SET). Generated 2026-07-07.
SET FOREIGN_KEY_CHECKS = 0;

-- ===== MEMBERS: 50,000,000 HP =====
UPDATE `weenie_properties_attribute_2nd` SET `init_Level`=50000000, `current_Level`=50000000
WHERE `object_Id` IN (730000009,730000016,730000019,730000020,730000023,730000024,730000025,730000026,730000027,730000028,730000030,730000031,730000032,730000033,730000034,730000038,730000039,730000040,730000041,730000042,730000043,730000044,730000045,730000050,730000052,730000053,730000054,730000055,730000056,730000057,730000058,730000059,730000061,730000062,730000063,730000064,730000068,730000069,730000070,730000071)
  AND `type`=1;

-- ===== BOSSES: 120,000,000 HP =====
UPDATE `weenie_properties_attribute_2nd` SET `init_Level`=120000000, `current_Level`=120000000
WHERE `object_Id` IN (730000035,730000036,730000037,730000101,730000102,730000103,730000104,730000105,730000106,730000107,730000108,730000109,730000110,730000111,730000112,730000113,730000114,730000115,730000116)
